#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define db long double
const int N=2005;
int n,m,mxnum,ansl,ansr,ansop,pre[N][N][2];
db x[N],y[N],dp[N][N][2],ans=1e18,mx=-1e18;
db fun(int a,int b)
{
	return sqrt((x[a]-x[b])*(x[a]-x[b])+(y[a]-y[b])*(y[a]-y[b]));
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>x[i]>>y[i];
		x[i+n]=x[i];
		y[i+n]=y[i];
		if(y[i]>mx)
		{
			mx=y[i];
			mxnum=i;
		}
	}
	for(int i=1;i<=n*2;i++)
	{
		for(int j=1;j<=n*2;j++) 
		{
			dp[i][j][0]=dp[i][j][1]=1e18;
		}
	}
	dp[mxnum][mxnum][0]=dp[mxnum][mxnum][1]=dp[mxnum+n][mxnum+n][0]=dp[mxnum+n][mxnum+n][1]=0;
	for(int len=2;len<=n;len++)
	{
		for(int l=1,r=len;r<=n*2;l++,r++)
		{
			db tmp1=dp[l+1][r][0]+fun(l+1,l),tmp2=dp[l+1][r][1]+fun(r,l);
			if(tmp1<tmp2)
			{
				dp[l][r][0]=tmp1;
				pre[l][r][0]=0;
			}
			else
			{
				dp[l][r][0]=tmp2;
				pre[l][r][0]=1;
			}
			tmp1=dp[l][r-1][0]+fun(l,r),tmp2=dp[l][r-1][1]+fun(r-1,r);
			if(tmp1<tmp2)
			{
				dp[l][r][1]=tmp1;
				pre[l][r][1]=0;
			}
			else
			{
				dp[l][r][1]=tmp2;
				pre[l][r][1]=1;
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		if(dp[i][i+n-1][0]<ans)
		{
			ans=dp[i][i+n-1][0];
			ansl=i;
			ansr=i+n-1;
			ansop=0;
		}
		if(dp[i][i+n-1][1]<ans)
		{
			ans=dp[i][i+n-1][1];
			ansl=i;
			ansr=i+n-1;
			ansop=1;
		}
	}
//	cout<<ans<<"\n";
	vector<int> v;
	while(ansr>ansl)
	{
		if(ansop==0)
		{
			v.push_back(ansl);
			ansop=pre[ansl][ansr][0];
			ansl++;
		}
		else
		{
			v.push_back(ansr);
			ansop=pre[ansl][ansr][1];
			ansr--;
		}
	}
	v.push_back(ansl);
	for(int i=v.size()-1;i>=0;i--)
	{
		cout<<(v[i]-1)%n+1<<" ";
	}
	return 0;
}
